{
  "name": "Mapeamento de Travas Emocionais",
  "description": "Uma ferramenta de autoanálise para identificar bloqueios emocionais baseada em 10 travas fundamentais, gerando um gráfico personalizado de desempenho."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Question {
  id: string;
  text: string;
}

export interface TravaCategory {
  id: string;
  title: string;
  description: string;
  questions: Question[];
}

export interface UserData {
  name: string;
  phone: string;
}

export type Answers = Record<string, number>; // questionId -> score

export interface TravaResult {
  travaTitle: string;
  average: number;
  totalScore: number;
}

import React, { useState, useMemo } from 'react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Lock, User, Phone, CheckCircle, ChevronRight, BarChart2, Brain, Play } from 'lucide-react';
import { TRAVAS_DATA } from './constants';
import { UserData, Answers, TravaResult } from './types';

export default function App() {
  const [step, setStep] = useState<'intro' | 'quiz' | 'results'>('intro');
  const [userData, setUserData] = useState<UserData>({ name: '', phone: '' });
  const [answers, setAnswers] = useState<Answers>({});

  // Quiz Navigation State
  const [currentTravaIndex, setCurrentTravaIndex] = useState(0);

  const handleStart = () => {
    if (userData.name.trim().length > 0 && userData.phone.trim().length > 0) {
      setStep('quiz');
      window.scrollTo(0, 0);
    } else {
      alert('Por favor, preencha seu nome e telefone para iniciar.');
    }
  };

  const handleAnswer = (questionId: string, value: number) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleNextTrava = () => {
    if (currentTravaIndex < TRAVAS_DATA.length - 1) {
      setCurrentTravaIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    } else {
      setStep('results');
      window.scrollTo(0, 0);
    }
  };

  const calculateResults = useMemo((): TravaResult[] => {
    return TRAVAS_DATA.map(trava => {
      let total = 0;
      trava.questions.forEach(q => {
        total += answers[q.id] || 0;
      });
      const average = total / trava.questions.length;
      return {
        travaTitle: trava.title.replace('Trava da ', '').replace('Trava ', ''), // Shorten name for chart
        average: parseFloat(average.toFixed(1)),
        totalScore: total
      };
    });
  }, [answers]);

  // Check if current page is fully answered
  const isCurrentPageComplete = useMemo(() => {
    const currentTrava = TRAVAS_DATA[currentTravaIndex];
    return currentTrava.questions.every(q => answers[q.id] !== undefined);
  }, [answers, currentTravaIndex]);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans selection:bg-blue-200">

      {/* Header */}
      <header className="bg-white shadow-sm sticky top-0 z-20">
        <div className="max-w-3xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Lock size={20} />
            </div>
            <h1 className="text-lg font-bold text-gray-800 leading-tight">
              Mapeamento <br className="sm:hidden"/> de Travas
            </h1>
          </div>
          {step === 'quiz' && (
            <div className="text-sm font-medium text-gray-500">
              Trava {currentTravaIndex + 1} de {TRAVAS_DATA.length}
            </div>
          )}
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-8 pb-24">

        {/* STEP 1: INTRO & FORM */}
        {step === 'intro' && (
          <div className="space-y-8 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
              <div className="text-center mb-8">
                <div className="bg-blue-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                  <Brain size={40} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">Descubra seus Bloqueios</h2>
                <p className="text-gray-600">
                  Responda a perguntas sobre 10 áreas fundamentais da vida para identificar quais travas emocionais estão limitando seu potencial.
                </p>
              </div>

              <div className="space-y-5">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu Nome</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="text"
                      placeholder="Digite seu nome completo"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.name}
                      onChange={(e) => setUserData({ ...userData, name: e.target.value })}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu WhatsApp</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="tel"
                      placeholder="(00) 00000-0000"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.phone}
                      onChange={(e) => setUserData({ ...userData, phone: e.target.value })}
                    />
                  </div>
                </div>

                <button
                  onClick={handleStart}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 mt-4"
                >
                  <span>Iniciar Mapeamento</span>
                  <Play size={20} fill="currentColor" />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4 text-center text-xs text-gray-500">
              <div className="bg-white p-4 rounded-lg shadow-sm">
                <span className="block font-bold text-gray-800 text-lg mb-1">10</span>
                Travas Analisadas
              </div>
              <div className="bg-white p-4 rounded-lg shadow-sm">
                <span className="block font-bold text-gray-800 text-lg mb-1">50</span>
                Perguntas Rápidas
              </div>
            </div>
          </div>
        )}

        {/* STEP 2: QUIZ */}
        {step === 'quiz' && (
          <div className="space-y-6">
            <div className="bg-white rounded-2xl shadow-md p-6 border-l-4 border-blue-500">
              <h2 className="text-xl font-bold text-gray-800 mb-2">{TRAVAS_DATA[currentTravaIndex].title}</h2>
              <p className="text-gray-600 text-sm leading-relaxed">{TRAVAS_DATA[currentTravaIndex].description}</p>
            </div>

            <div className="space-y-6">
              {TRAVAS_DATA[currentTravaIndex].questions.map((question, qIdx) => (
                <div key={question.id} className="bg-white rounded-xl shadow-sm p-5 sm:p-6 transition-colors border border-transparent hover:border-blue-100">
                  <div className="flex justify-between items-start mb-4 gap-4">
                    <span className="bg-gray-100 text-gray-500 text-xs font-bold px-2 py-1 rounded">
                      {qIdx + 1}/5
                    </span>
                    <h3 className="text-gray-800 font-medium flex-1 pt-0.5">{question.text}</h3>
                  </div>

                  <div className="pt-2">
                    <div className="flex justify-between text-xs text-gray-500 mb-2 uppercase tracking-wide">
                      <span>Discordo (0)</span>
                      <span>Concordo Muito (10)</span>
                    </div>
                    <input
                      type="range"
                      min="0"
                      max="10"
                      step="1"
                      value={answers[question.id] ?? 0}
                      onChange={(e) => handleAnswer(question.id, parseInt(e.target.value))}
                      className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600 focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                    />
                    <div className="mt-3 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full text-sm font-bold ${
                        (answers[question.id] ?? 0) > 7 ? 'bg-red-100 text-red-700' :
                        (answers[question.id] ?? 0) > 4 ? 'bg-yellow-100 text-yellow-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        Nota: {answers[question.id] ?? 0}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 z-10 shadow-lg">
              <div className="max-w-3xl mx-auto flex items-center justify-between">
                <div className="w-full bg-gray-200 rounded-full h-2.5 max-w-[100px] hidden sm:block mr-4">
                  <div 
                    className="bg-blue-600 h-2.5 rounded-full transition-all duration-300" 
                    style={{ width: `${((currentTravaIndex) / TRAVAS_DATA.length) * 100}%` }}
                  ></div>
                </div>

                <button
                  onClick={handleNextTrava}
                  disabled={!isCurrentPageComplete}
                  className={`w-full sm:w-auto px-8 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
                    isCurrentPageComplete 
                      ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-md transform hover:-translate-y-1' 
                      : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? 'Ver Resultado' : 'Próxima Trava'}
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? <BarChart2 size={18} /> : <ChevronRight size={18} />}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* STEP 3: RESULTS */}
        {step === 'results' && (
          <div className="space-y-8 animate-fade-in-up">
            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100 text-center">
               <div className="mb-2 uppercase tracking-wider text-xs font-bold text-gray-400">Relatório de</div>
               <h2 className="text-3xl font-bold text-blue-900 mb-1">{userData.name}</h2>
               <p className="text-gray-500 text-sm mb-6">{userData.phone}</p>

               <div className="w-full h-1 bg-gray-100 rounded mb-8"></div>

               <h3 className="text-xl font-semibold text-gray-800 mb-4 flex items-center justify-center gap-2">
                 <CheckCircle className="text-green-500" size={24}/>
                 Mapa Radar das Travas
               </h3>

               <div className="w-full h-[400px] flex items-center justify-center -ml-4">
                 <ResponsiveContainer width="100%" height="100%">
                   <RadarChart cx="50%" cy="50%" outerRadius="80%" data={calculateResults}>
                     <PolarGrid gridType="polygon" />
                     <PolarAngleAxis dataKey="travaTitle" tick={{ fill: '#4B5563', fontSize: 12 }} />
                     <PolarRadiusAxis angle={30} domain={[0, 10]} tickCount={6} />
                     <Radar
                       name="Média"
                       dataKey="average"
                       stroke="#2563EB"
                       strokeWidth={3}
                       fill="#3B82F6"
                       fillOpacity={0.5}
                     />
                     <Tooltip 
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                     />
                   </RadarChart>
                 </ResponsiveContainer>
               </div>

               <p className="text-sm text-gray-500 mt-4 italic">
                 Quanto mais próximo da borda externa (10), maior é o bloqueio nesta área.
               </p>
            </div>

            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
               <h3 className="text-xl font-semibold text-gray-800 mb-6 flex items-center gap-2">
                 <BarChart2 className="text-blue-500" size={24}/>
                 Detalhamento por Área (Média 0-10)
               </h3>

               <div className="w-full h-[300px]">
                 <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={calculateResults} layout="vertical" margin={{ left: 40, right: 40 }}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                      <XAxis type="number" domain={[0, 10]} hide />
                      <YAxis dataKey="travaTitle" type="category" width={100} tick={{ fontSize: 12, fontWeight: 500 }} />
                      <Tooltip 
                        cursor={{fill: 'transparent'}}
                        contentStyle={{ borderRadius: '8px' }}
                      />
                      <Bar dataKey="average" name="Média" radius={[0, 4, 4, 0]}>
                         {calculateResults.map((entry, index) => (
                           <cell key={`cell-${index}`} fill={entry.average > 7 ? '#EF4444' : entry.average > 4 ? '#F59E0B' : '#10B981'} />
                         ))}
                      </Bar>
                    </BarChart>
                 </ResponsiveContainer>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {calculateResults.filter(r => r.average >= 7).map(high => (
                <div key={high.travaTitle} className="bg-red-50 border border-red-100 p-4 rounded-xl">
                  <div className="flex items-center justify-between mb-2">
                    <h4 className="font-bold text-red-800">{high.travaTitle}</h4>
                    <span className="bg-red-200 text-red-800 text-xs font-bold px-2 py-1 rounded">Alta: {high.average}</span>
                  </div>
                  <p className="text-xs text-red-600">Este é um bloqueio significativo que merece atenção prioritária.</p>
                </div>
              ))}
            </div>

            <div className="text-center pt-8">
              <button 
                onClick={() => window.print()}
                className="text-blue-600 font-medium hover:underline text-sm"
              >
                Imprimir ou Salvar PDF
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

