import { TRAVAS_DATA } from './constants';
import { UserData, Answers, TravaResult } from './types';

export default function App() {
  // Steps: 
  // 'intro': User start screen
  // 'quiz': User answering questions
  // 'submission': User finished, needs to send data to admin
  // 'admin_login': Admin entering password
  // 'results': Admin viewing charts
  const [step, setStep] = useState<'intro' | 'quiz' | 'submission' | 'admin_login' | 'results'>('intro');

  const [userData, setUserData] = useState<UserData>({ name: '', phone: '' });
  const [answers, setAnswers] = useState<Answers>({});
  const [adminPassword, setAdminPassword] = useState('');
  const [pendingData, setPendingData] = useState<{userData: UserData, answers: Answers} | null>(null);

  // Quiz Navigation State
  const [currentTravaIndex, setCurrentTravaIndex] = useState(0);

  // Check for Admin Data in URL on load
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const dataParam = params.get('data');
    if (dataParam) {
      try {
        const decoded = JSON.parse(atob(dataParam));
        setPendingData(decoded);
        setStep('admin_login');
      } catch (e) {
        console.error("Invalid data param");
      }
    }
  }, []);

  const handleStart = () => {
    if (userData.name.trim().length > 0 && userData.phone.trim().length > 0) {
      setStep('quiz');
      window.scrollTo(0, 0);
    } else {
      alert('Por favor, preencha seu nome e telefone para iniciar.');
    }
  };

  const handleAnswer = (questionId: string, value: number) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleNextTrava = () => {
    if (currentTravaIndex < TRAVAS_DATA.length - 1) {
      setCurrentTravaIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    } else {
      // User finished the quiz
      setStep('submission');
      window.scrollTo(0, 0);
    }
  };

  const calculateResults = useMemo((): TravaResult[] => {
    return TRAVAS_DATA.map(trava => {
      let total = 0;
      trava.questions.forEach(q => {
        total += answers[q.id] || 0;
      });
      const average = total / trava.questions.length;
      return {
        travaTitle: trava.title.replace('Trava da ', '').replace('Trava ', ''), // Shorten name for chart
        average: parseFloat(average.toFixed(1)),
        totalScore: total
      };
    });
  }, [answers]);

  const isCurrentPageComplete = useMemo(() => {
    const currentTrava = TRAVAS_DATA[currentTravaIndex];
    return currentTrava.questions.every(q => answers[q.id] !== undefined);
  }, [answers, currentTravaIndex]);

  // --- ACTIONS ---

  // 1. User sends data to Admin via WhatsApp
  const sendDataToAdmin = () => {
    // Pack data
    const payload = { userData, answers };
    const encoded = btoa(JSON.stringify(payload));

    // Generate Link that opens this app in 'admin_login' mode
    const appUrl = `${window.location.origin}${window.location.pathname}?data=${encoded}`;

    const message = `*Nova Análise de Travas Concluída*\n` +
      `*Nome:* ${userData.name}\n` +
      `*Telefone:* ${userData.phone}\n\n` +
      `Clique no link abaixo para visualizar os gráficos e gerar o relatório:\n${appUrl}`;

    const phoneNumber = '5547992785605'; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
  };

  // 2. Admin Login Logic
  const handleAdminLogin = () => {
    if (adminPassword === 'admin') { // Simple password
      if (pendingData) {
        setUserData(pendingData.userData);
        setAnswers(pendingData.answers);
        setStep('results');
      } else {
        alert("Nenhum dado de análise encontrado no link.");
        setStep('intro');
      }
    } else {
      alert("Senha incorreta.");
    }
  };

  // 3. Admin sends "Ready" message back to User
  const notifyUserViaWhatsApp = () => {
    const message = `Olá ${userData.name}, sua análise de Travas Emocionais está pronta!`;
    // Format user phone (remove non-digits)
    const cleanPhone = userData.phone.replace(/\D/g, '');
    window.open(`https://wa.me/55${cleanPhone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans selection:bg-blue-200">

      {/* Header */}
      <header className="bg-white shadow-sm sticky top-0 z-20 print:hidden">
        <div className="max-w-3xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Lock size={20} />
            </div>
            <h1 className="text-lg font-bold text-gray-800 leading-tight">
              Mapeamento <br className="sm:hidden"/> de Travas
            </h1>
          </div>
          {step === 'quiz' && (
            <div className="text-sm font-medium text-gray-500">
              Trava {currentTravaIndex + 1} de {TRAVAS_DATA.length}
            </div>
          )}
          {step === 'results' && (
             <div className="text-xs bg-red-100 text-red-800 px-2 py-1 rounded font-bold uppercase">
               Modo Administrador
             </div>
          )}
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-8 pb-24">

        {/* STEP 1: INTRO & FORM */}
        {step === 'intro' && (
          <div className="space-y-8 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
              <div className="text-center mb-6">
                <div className="bg-blue-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                  <Brain size={40} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">Descubra seus Bloqueios</h2>
                <p className="text-gray-600">
                  Ferramenta de autoanálise para identificar travas emocionais.
                </p>
              </div>

              {/* Video Presentation */}
              <div className="rounded-xl overflow-hidden shadow-md aspect-video bg-gray-100">
                <iframe 
                  className="w-full h-full"
                  src="https://www.youtube.com/embed/b_dPrk4g_ok" 
                  title="Apresentação Mapeamento de Travas"
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                  allowFullScreen
                ></iframe>
              </div>

              {/* NEW TEXT REQUIRED */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 text-sm text-blue-800 leading-relaxed text-center">
                Faça o formulario com calma e reflita cada pergunta pensando no hoje, no que esta vivendo agora no seu momento presente. Terminando as informações da travas serão enviada no seu celular.
              </div>

              <div className="space-y-5 pt-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu Nome</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="text"
                      placeholder="Digite seu nome completo"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.name}
                      onChange={(e) => setUserData({ ...userData, name: e.target.value })}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu WhatsApp</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="tel"
                      placeholder="(00) 00000-0000"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.phone}
                      onChange={(e) => setUserData({ ...userData, phone: e.target.value })}
                    />
                  </div>
                </div>

                <button
                  onClick={handleStart}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 mt-4"
                >
                  <span>Iniciar Mapeamento</span>
                  <Play size={20} fill="currentColor" />
                </button>
              </div>
            </div>

            <div className="text-center">
                <button 
                    onClick={() => setStep('admin_login')}
                    className="text-xs text-gray-400 hover:text-gray-600 font-medium underline"
                >
                    Acesso Administrativo
                </button>
            </div>
          </div>
        )}

        {/* STEP 2: QUIZ */}
        {step === 'quiz' && (
          <div className="space-y-6">
            <div className="bg-white rounded-2xl shadow-md p-6 border-l-4 border-blue-500">
              <h2 className="text-xl font-bold text-gray-800 mb-2">{TRAVAS_DATA[currentTravaIndex].title}</h2>
              <p className="text-gray-600 text-sm leading-relaxed">{TRAVAS_DATA[currentTravaIndex].description}</p>
            </div>

            <div className="space-y-6">
              {TRAVAS_DATA[currentTravaIndex].questions.map((question, qIdx) => (
                <div key={question.id} className="bg-white rounded-xl shadow-sm p-5 sm:p-6 transition-colors border border-transparent hover:border-blue-100">
                  <div className="flex justify-between items-start mb-4 gap-4">
                    <span className="bg-gray-100 text-gray-500 text-xs font-bold px-2 py-1 rounded">
                      {qIdx + 1}/5
                    </span>
                    <h3 className="text-gray-800 font-medium flex-1 pt-0.5">{question.text}</h3>
                  </div>

                  <div className="pt-2">
                    <div className="flex justify-between text-xs text-gray-500 mb-2 uppercase tracking-wide">
                      <span>Discordo (0)</span>
                      <span>Concordo Muito (10)</span>
                    </div>
                    <input
                      type="range"
                      min="0"
                      max="10"
                      step="1"
                      value={answers[question.id] ?? 0}
                      onChange={(e) => handleAnswer(question.id, parseInt(e.target.value))}
                      className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600 focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                    />
                    <div className="mt-3 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full text-sm font-bold ${
                        (answers[question.id] ?? 0) > 7 ? 'bg-red-100 text-red-700' :
                        (answers[question.id] ?? 0) > 4 ? 'bg-yellow-100 text-yellow-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        Nota: {answers[question.id] ?? 0}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 z-10 shadow-lg">
              <div className="max-w-3xl mx-auto flex items-center justify-between">
                <div className="w-full bg-gray-200 rounded-full h-2.5 max-w-[100px] hidden sm:block mr-4">
                  <div 
                    className="bg-blue-600 h-2.5 rounded-full transition-all duration-300" 
                    style={{ width: `${((currentTravaIndex) / TRAVAS_DATA.length) * 100}%` }}
                  ></div>
                </div>

                <button
                  onClick={handleNextTrava}
                  disabled={!isCurrentPageComplete}
                  className={`w-full sm:w-auto px-8 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
                    isCurrentPageComplete 
                      ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-md transform hover:-translate-y-1' 
                      : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? 'Concluir' : 'Próxima Trava'}
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? <CheckCircle size={18} /> : <ChevronRight size={18} />}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* STEP 3: SUBMISSION (USER VIEW) */}
        {step === 'submission' && (
          <div className="space-y-8 animate-fade-in text-center">
            <div className="bg-white rounded-2xl shadow-lg p-10 border border-gray-100">
               <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
                 <CheckCircle size={40} />
               </div>
               <h2 className="text-2xl font-bold text-gray-800 mb-4">Análise Concluída!</h2>
               <p className="text-gray-600 mb-8 leading-relaxed">
                 Obrigado por responder com sinceridade. Para gerar seu gráfico e receber a análise detalhada, você precisa enviar seus dados para o administrador.
               </p>

               <button 
                 onClick={sendDataToAdmin}
                 className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 animate-bounce-subtle"
               >
                 <Send size={20} />
                 Enviar para Análise (WhatsApp)
               </button>
               <p className="text-xs text-gray-400 mt-4">
                 Ao clicar, você será redirecionado para o WhatsApp do administrador.
               </p>
            </div>
          </div>
        )}

        {/* STEP 4: ADMIN LOGIN */}
        {step === 'admin_login' && (
           <div className="space-y-8 animate-fade-in max-w-md mx-auto">
             <div className="bg-white rounded-2xl shadow-lg p-8 border border-gray-100">
               <div className="text-center mb-6">
                 <div className="bg-gray-800 text-white w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                   <ShieldCheck size={32} />
                 </div>
                 <h2 className="text-xl font-bold text-gray-800">Acesso Administrativo</h2>
                 <p className="text-sm text-gray-500 mt-2">
                   {pendingData ? `Analisando dados de: ${pendingData.userData.name}` : 'Entre para acessar o sistema'}
                 </p>
               </div>

               <div className="space-y-4">
                 <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Senha de Admin</label>
                   <input
                      type="password"
                      className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-gray-500 outline-none"
                      placeholder="Digite a senha..."
                      value={adminPassword}
                      onChange={(e) => setAdminPassword(e.target.value)}
                    />
                 </div>
                 <button
                    onClick={handleAdminLogin}
                    className="w-full bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 rounded-xl transition-all"
                 >
                   Entrar e Visualizar
                 </button>
               </div>
             </div>

             <div className="text-center">
                <button onClick={() => setStep('intro')} className="text-gray-500 underline text-sm">
                    Voltar para Início
                </button>
             </div>
           </div>
        )}

        {/* STEP 5: RESULTS (ADMIN ONLY) */}
        {step === 'results' && (
          <div className="space-y-8 animate-fade-in-up">
            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100 text-center">
               <div className="mb-2 uppercase tracking-wider text-xs font-bold text-gray-400">Relatório de</div>
               <h2 className="text-3xl font-bold text-blue-900 mb-1">{userData.name}</h2>
               <p className="text-gray-500 text-sm mb-6">{userData.phone}</p>

               <div className="w-full h-1 bg-gray-100 rounded mb-8"></div>

               <h3 className="text-xl font-semibold text-gray-800 mb-4 flex items-center justify-center gap-2">
                 <CheckCircle className="text-green-500" size={24}/>
                 Mapa Radar das Travas
               </h3>

               <div className="w-full h-[400px] flex items-center justify-center -ml-4">
                 <ResponsiveContainer width="100%" height="100%">
                   <RadarChart cx="50%" cy="50%" outerRadius="80%" data={calculateResults}>
                     <PolarGrid gridType="polygon" />
                     <PolarAngleAxis dataKey="travaTitle" tick={{ fill: '#4B5563', fontSize: 12 }} />
                     <PolarRadiusAxis angle={30} domain={[0, 10]} tickCount={6} />
                     <Radar
                       name="Média"
                       dataKey="average"
                       stroke="#2563EB"
                       strokeWidth={3}
                       fill="#3B82F6"
                       fillOpacity={0.5}
                     />
                     <Tooltip 
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                     />
                   </RadarChart>
                 </ResponsiveContainer>
               </div>

               <p className="text-sm text-gray-500 mt-4 italic">
                 Quanto mais próximo da borda externa (10), maior é o bloqueio nesta área.
               </p>
            </div>

            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
               <h3 className="text-xl font-semibold text-gray-800 mb-6 flex items-center gap-2">
                 <BarChart2 className="text-blue-500" size={24}/>
                 Detalhamento por Área (Média 0-10)
               </h3>

               <div className="w-full h-[300px]">
                 <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={calculateResults} layout="vertical" margin={{ left: 40, right: 40 }}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                      <XAxis type="number" domain={[0, 10]} hide />
                      <YAxis dataKey="travaTitle" type="category" width={100} tick={{ fontSize: 12, fontWeight: 500 }} />
                      <Tooltip 
                        cursor={{fill: 'transparent'}}
                        contentStyle={{ borderRadius: '8px' }}
                      />
                      <Bar dataKey="average" name="Média" radius={[0, 4, 4, 0]}>
                         {calculateResults.map((entry, index) => (
                           <Cell key={`cell-${index}`} fill={entry.average > 5 ? '#EF4444' : entry.average > 3 ? '#F59E0B' : '#10B981'} />
                         ))}
                      </Bar>
                    </BarChart>
                 </ResponsiveContainer>
               </div>
            </div>

            {/* Priority Alerts (> 5) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {calculateResults.filter(r => r.average > 5).map(high => (
                <div key={high.travaTitle} className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-start gap-3">
                  <div className="bg-red-100 p-2 rounded-full text-red-600 mt-1">
                    <AlertTriangle size={20} />
                  </div>
                  <div>
                    <div className="flex items-center justify-between mb-1 gap-2">
                      <h4 className="font-bold text-red-800">{high.travaTitle}</h4>
                      <span className="bg-red-200 text-red-800 text-xs font-bold px-2 py-1 rounded">Média: {high.average}</span>
                    </div>
                    <p className="text-sm text-red-600 font-medium">Merece atenção prioritária.</p>
                  </div>
                </div>
              ))}
            </div>

            {/* Admin Action Buttons */}
            <div className="flex flex-col sm:flex-row justify-center gap-4 pt-8 print:hidden">
              <button 
                onClick={() => window.print()}
                className="bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1"
              >
                <Printer size={20} />
                Imprimir / Salvar PDF
              </button>

              <button 
                onClick={notifyUserViaWhatsApp}
                className="bg-green-500 hover:bg-green-600 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1"
              >
                <MessageCircle size={20} />
                Avisar Cliente (WhatsApp)
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export interface Question {
  id: string;
  text: string;
}

export interface TravaCategory {
  id: string;
  title: string;
  description: string;
  questions: Question[];
}

export interface UserData {
  name: string;
  phone: string;
}

export type Answers = Record<string, number>; // questionId -> score

export interface TravaResult {
  travaTitle: string;
  average: number;
  totalScore: number;
}

export interface Submission {
  id: string;
  submittedAt: string;
  userData: UserData;
  answers: Answers;
}

import React, { useState, useMemo, useEffect } from 'react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Cell } from 'recharts';
import { Lock, User, Phone, CheckCircle, ChevronRight, BarChart2, Brain, Play, Printer, MessageCircle, AlertTriangle, ShieldCheck, Send, Database, Trash2, Calendar, ArrowLeft } from 'lucide-react';
import { TRAVAS_DATA } from './constants';
import { UserData, Answers, TravaResult, Submission } from './types';

export default function App() {
  // Steps: 
  // 'intro': User start screen
  // 'quiz': User answering questions
  // 'submission': User finished, needs to send data to admin
  // 'admin_login': Admin entering password
  // 'admin_dashboard': List of all saved submissions
  // 'results': Admin viewing charts
  const [step, setStep] = useState<'intro' | 'quiz' | 'submission' | 'admin_login' | 'admin_dashboard' | 'results'>('intro');

  const [userData, setUserData] = useState<UserData>({ name: '', phone: '' });
  const [answers, setAnswers] = useState<Answers>({});

  // Admin State
  const [adminPassword, setAdminPassword] = useState('');
  const [pendingData, setPendingData] = useState<Submission | null>(null);
  const [dbHistory, setDbHistory] = useState<Submission[]>([]);

  // Quiz Navigation State
  const [currentTravaIndex, setCurrentTravaIndex] = useState(0);

  // Load DB on mount
  useEffect(() => {
    const stored = localStorage.getItem('travas_db_v1');
    if (stored) {
      try {
        setDbHistory(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  // Check for Admin Data in URL on load
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const dataParam = params.get('data');
    if (dataParam) {
      try {
        const decoded: Submission = JSON.parse(atob(dataParam));
        // Backward compatibility check or basic validation
        if (decoded.userData && decoded.answers) {
           setPendingData(decoded);
           setStep('admin_login');
        }
      } catch (e) {
        console.error("Invalid data param");
      }
    }
  }, []);

  const saveToHistory = (submission: Submission) => {
    setDbHistory(prev => {
      // Avoid duplicates by ID
      const exists = prev.find(p => p.id === submission.id);
      let newHistory;
      if (exists) {
        newHistory = prev.map(p => p.id === submission.id ? submission : p);
      } else {
        newHistory = [submission, ...prev];
      }
      localStorage.setItem('travas_db_v1', JSON.stringify(newHistory));
      return newHistory;
    });
  };

  const deleteFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Tem certeza que deseja excluir este registro?')) {
      const newHistory = dbHistory.filter(item => item.id !== id);
      setDbHistory(newHistory);
      localStorage.setItem('travas_db_v1', JSON.stringify(newHistory));
    }
  };

  const handleStart = () => {
    if (userData.name.trim().length > 0 && userData.phone.trim().length > 0) {
      setStep('quiz');
      window.scrollTo(0, 0);
    } else {
      alert('Por favor, preencha seu nome e telefone para iniciar.');
    }
  };

  const handleAnswer = (questionId: string, value: number) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleNextTrava = () => {
    if (currentTravaIndex < TRAVAS_DATA.length - 1) {
      setCurrentTravaIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    } else {
      // User finished the quiz
      setStep('submission');
      window.scrollTo(0, 0);
    }
  };

  const calculateResults = useMemo((): TravaResult[] => {
    return TRAVAS_DATA.map(trava => {
      let total = 0;
      trava.questions.forEach(q => {
        total += answers[q.id] || 0;
      });
      const average = total / trava.questions.length;
      return {
        travaTitle: trava.title.replace('Trava da ', '').replace('Trava ', ''), // Shorten name for chart
        average: parseFloat(average.toFixed(1)),
        totalScore: total
      };
    });
  }, [answers]);

  const isCurrentPageComplete = useMemo(() => {
    const currentTrava = TRAVAS_DATA[currentTravaIndex];
    return currentTrava.questions.every(q => answers[q.id] !== undefined);
  }, [answers, currentTravaIndex]);

  // --- ACTIONS ---

  // 1. User sends data to Admin via WhatsApp
  const sendDataToAdmin = () => {
    // Pack data with ID and Timestamp
    const payload: Submission = { 
      id: Date.now().toString(),
      submittedAt: new Date().toISOString(),
      userData, 
      answers 
    };
    const encoded = btoa(JSON.stringify(payload));

    // Generate Link that opens this app in 'admin_login' mode
    const appUrl = `${window.location.origin}${window.location.pathname}?data=${encoded}`;

    const message = `*Nova Análise de Travas Concluída*\n` +
      `*Nome:* ${userData.name}\n` +
      `*Telefone:* ${userData.phone}\n\n` +
      `Clique no link abaixo para salvar no banco de dados e visualizar:\n${appUrl}`;

    const phoneNumber = '5547992785605'; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
  };

  // 2. Admin Login Logic
  const handleAdminLogin = () => {
    if (adminPassword === 'admin') { // Simple password
      if (pendingData) {
        // Save pending data immediately upon login
        saveToHistory(pendingData);
        setUserData(pendingData.userData);
        setAnswers(pendingData.answers);
        setStep('results');
      } else {
        // Direct access, go to dashboard
        setStep('admin_dashboard');
      }
    } else {
      alert("Senha incorreta.");
    }
  };

  // 3. Admin sends "Ready" message back to User
  const notifyUserViaWhatsApp = () => {
    const message = `Olá ${userData.name}, sua análise de Travas Emocionais está pronta!`;
    // Format user phone (remove non-digits)
    const cleanPhone = userData.phone.replace(/\D/g, '');
    window.open(`https://wa.me/55${cleanPhone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  // Load a historic item
  const loadSubmission = (sub: Submission) => {
    setUserData(sub.userData);
    setAnswers(sub.answers);
    setStep('results');
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans selection:bg-blue-200">

      {/* Header */}
      <header className="bg-white shadow-sm sticky top-0 z-20 print:hidden">
        <div className="max-w-3xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Lock size={20} />
            </div>
            <h1 className="text-lg font-bold text-gray-800 leading-tight">
              Mapeamento <br className="sm:hidden"/> de Travas
            </h1>
          </div>
          {step === 'quiz' && (
            <div className="text-sm font-medium text-gray-500">
              Trava {currentTravaIndex + 1} de {TRAVAS_DATA.length}
            </div>
          )}
          {(step === 'results' || step === 'admin_dashboard') && (
             <div className="text-xs bg-red-100 text-red-800 px-2 py-1 rounded font-bold uppercase flex items-center gap-1">
               <ShieldCheck size={12} /> Admin
             </div>
          )}
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-8 pb-24">

        {/* STEP 1: INTRO & FORM */}
        {step === 'intro' && (
          <div className="space-y-8 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
              <div className="text-center mb-6">
                <div className="bg-blue-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                  <Brain size={40} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">Descubra seus Bloqueios</h2>
                <p className="text-gray-600">
                  Ferramenta de autoanálise para identificar travas emocionais.
                </p>
              </div>

              {/* Video Presentation */}
              <div className="rounded-xl overflow-hidden shadow-md aspect-video bg-gray-100">
                <iframe 
                  className="w-full h-full"
                  src="https://www.youtube.com/embed/b_dPrk4g_ok" 
                  title="Apresentação Mapeamento de Travas"
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                  allowFullScreen
                ></iframe>
              </div>

              {/* NEW TEXT REQUIRED */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 text-sm text-blue-800 leading-relaxed text-center">
                Faça o formulario com calma e reflita cada pergunta pensando no hoje, no que esta vivendo agora no seu momento presente. Terminando as informações da travas serão enviada no seu celular.
              </div>

              <div className="space-y-5 pt-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu Nome</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="text"
                      placeholder="Digite seu nome completo"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.name}
                      onChange={(e) => setUserData({ ...userData, name: e.target.value })}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu WhatsApp</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="tel"
                      placeholder="(00) 00000-0000"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.phone}
                      onChange={(e) => setUserData({ ...userData, phone: e.target.value })}
                    />
                  </div>
                </div>

                <button
                  onClick={handleStart}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 mt-4"
                >
                  <span>Iniciar Mapeamento</span>
                  <Play size={20} fill="currentColor" />
                </button>
              </div>
            </div>

            <div className="text-center">
                <button 
                    onClick={() => setStep('admin_login')}
                    className="text-xs text-gray-400 hover:text-gray-600 font-medium underline"
                >
                    Acesso Administrativo
                </button>
            </div>
          </div>
        )}

        {/* STEP 2: QUIZ */}
        {step === 'quiz' && (
          <div className="space-y-6">
            <div className="bg-white rounded-2xl shadow-md p-6 border-l-4 border-blue-500">
              <h2 className="text-xl font-bold text-gray-800 mb-2">{TRAVAS_DATA[currentTravaIndex].title}</h2>
              <p className="text-gray-600 text-sm leading-relaxed">{TRAVAS_DATA[currentTravaIndex].description}</p>
            </div>

            <div className="space-y-6">
              {TRAVAS_DATA[currentTravaIndex].questions.map((question, qIdx) => (
                <div key={question.id} className="bg-white rounded-xl shadow-sm p-5 sm:p-6 transition-colors border border-transparent hover:border-blue-100">
                  <div className="flex justify-between items-start mb-4 gap-4">
                    <span className="bg-gray-100 text-gray-500 text-xs font-bold px-2 py-1 rounded">
                      {qIdx + 1}/5
                    </span>
                    <h3 className="text-gray-800 font-medium flex-1 pt-0.5">{question.text}</h3>
                  </div>

                  <div className="pt-2">
                    <div className="flex justify-between text-xs text-gray-500 mb-2 uppercase tracking-wide">
                      <span>Discordo (0)</span>
                      <span>Concordo Muito (10)</span>
                    </div>
                    <input
                      type="range"
                      min="0"
                      max="10"
                      step="1"
                      value={answers[question.id] ?? 0}
                      onChange={(e) => handleAnswer(question.id, parseInt(e.target.value))}
                      className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600 focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                    />
                    <div className="mt-3 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full text-sm font-bold ${
                        (answers[question.id] ?? 0) > 7 ? 'bg-red-100 text-red-700' :
                        (answers[question.id] ?? 0) > 4 ? 'bg-yellow-100 text-yellow-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        Nota: {answers[question.id] ?? 0}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 z-10 shadow-lg">
              <div className="max-w-3xl mx-auto flex items-center justify-between">
                <div className="w-full bg-gray-200 rounded-full h-2.5 max-w-[100px] hidden sm:block mr-4">
                  <div 
                    className="bg-blue-600 h-2.5 rounded-full transition-all duration-300" 
                    style={{ width: `${((currentTravaIndex) / TRAVAS_DATA.length) * 100}%` }}
                  ></div>
                </div>

                <button
                  onClick={handleNextTrava}
                  disabled={!isCurrentPageComplete}
                  className={`w-full sm:w-auto px-8 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
                    isCurrentPageComplete 
                      ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-md transform hover:-translate-y-1' 
                      : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? 'Concluir' : 'Próxima Trava'}
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? <CheckCircle size={18} /> : <ChevronRight size={18} />}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* STEP 3: SUBMISSION (USER VIEW) */}
        {step === 'submission' && (
          <div className="space-y-8 animate-fade-in text-center">
            <div className="bg-white rounded-2xl shadow-lg p-10 border border-gray-100">
               <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
                 <CheckCircle size={40} />
               </div>
               <h2 className="text-2xl font-bold text-gray-800 mb-4">Análise Concluída!</h2>
               <p className="text-gray-600 mb-8 leading-relaxed">
                 Obrigado por responder com sinceridade. Para gerar seu gráfico e receber a análise detalhada, você precisa enviar seus dados para o administrador.
               </p>

               <button 
                 onClick={sendDataToAdmin}
                 className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 animate-bounce-subtle"
               >
                 <Send size={20} />
                 Enviar para Análise (WhatsApp)
               </button>
               <p className="text-xs text-gray-400 mt-4">
                 Ao clicar, você será redirecionado para o WhatsApp do administrador.
               </p>
            </div>
          </div>
        )}

        {/* STEP 4: ADMIN LOGIN */}
        {step === 'admin_login' && (
           <div className="space-y-8 animate-fade-in max-w-md mx-auto">
             <div className="bg-white rounded-2xl shadow-lg p-8 border border-gray-100">
               <div className="text-center mb-6">
                 <div className="bg-gray-800 text-white w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                   <ShieldCheck size={32} />
                 </div>
                 <h2 className="text-xl font-bold text-gray-800">Acesso Administrativo</h2>
                 <p className="text-sm text-gray-500 mt-2">
                   {pendingData ? `Analisando dados de: ${pendingData.userData.name}` : 'Entre para acessar o banco de dados'}
                 </p>
               </div>

               <div className="space-y-4">
                 <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Senha de Admin</label>
                   <input
                      type="password"
                      className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-gray-500 outline-none"
                      placeholder="Digite a senha..."
                      value={adminPassword}
                      onChange={(e) => setAdminPassword(e.target.value)}
                    />
                 </div>
                 <button
                    onClick={handleAdminLogin}
                    className="w-full bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 rounded-xl transition-all"
                 >
                   Entrar
                 </button>
               </div>
             </div>

             <div className="text-center">
                <button onClick={() => setStep('intro')} className="text-gray-500 underline text-sm">
                    Voltar para Início
                </button>
             </div>
           </div>
        )}

        {/* STEP 5: ADMIN DASHBOARD (DATABASE) */}
        {step === 'admin_dashboard' && (
          <div className="space-y-6 animate-fade-in">
             <div className="flex items-center justify-between mb-4">
                <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                  <Database className="text-blue-600" />
                  Banco de Dados
                </h2>
                <div className="bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-xs font-bold">
                  {dbHistory.length} Registros
                </div>
             </div>

             {dbHistory.length === 0 ? (
               <div className="bg-white rounded-xl p-8 text-center text-gray-500 border border-dashed border-gray-300">
                 <p>Nenhuma análise salva ainda.</p>
               </div>
             ) : (
               <div className="grid gap-3">
                 {dbHistory.map((item) => (
                   <div key={item.id} onClick={() => loadSubmission(item)} className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all cursor-pointer flex items-center justify-between group">
                      <div className="flex items-center gap-4">
                         <div className="bg-blue-50 w-10 h-10 rounded-full flex items-center justify-center text-blue-600 font-bold">
                           {item.userData.name.charAt(0).toUpperCase()}
                         </div>
                         <div>
                           <h4 className="font-bold text-gray-800">{item.userData.name}</h4>
                           <div className="flex items-center gap-3 text-xs text-gray-500">
                             <span className="flex items-center gap-1"><Phone size={12}/> {item.userData.phone}</span>
                             <span className="flex items-center gap-1"><Calendar size={12}/> {new Date(item.submittedAt || Date.now()).toLocaleDateString('pt-BR')}</span>
                           </div>
                         </div>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={(e) => deleteFromHistory(item.id, e)}
                          className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                          title="Excluir"
                        >
                          <Trash2 size={18} />
                        </button>
                        <ChevronRight className="text-gray-300 group-hover:text-blue-500" />
                      </div>
                   </div>
                 ))}
               </div>
             )}
          </div>
        )}

        {/* STEP 6: RESULTS (ADMIN ONLY) */}
        {step === 'results' && (
          <div className="space-y-8 animate-fade-in-up">

            {/* Nav Back */}
            <button 
              onClick={() => setStep('admin_dashboard')}
              className="flex items-center gap-2 text-gray-500 hover:text-gray-800 font-medium transition-colors"
            >
              <ArrowLeft size={18} /> Voltar para o Painel
            </button>

            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100 text-center">
               <div className="mb-2 uppercase tracking-wider text-xs font-bold text-gray-400">Relatório de</div>
               <h2 className="text-3xl font-bold text-blue-900 mb-1">{userData.name}</h2>
               <p className="text-gray-500 text-sm mb-6">{userData.phone}</p>

               <div className="w-full h-1 bg-gray-100 rounded mb-8"></div>

               <h3 className="text-xl font-semibold text-gray-800 mb-4 flex items-center justify-center gap-2">
                 <CheckCircle className="text-green-500" size={24}/>
                 Mapa Radar das Travas
               </h3>

               <div className="w-full h-[400px] flex items-center justify-center -ml-4">
                 <ResponsiveContainer width="100%" height="100%">
                   <RadarChart cx="50%" cy="50%" outerRadius="80%" data={calculateResults}>
                     <PolarGrid gridType="polygon" />
                     <PolarAngleAxis dataKey="travaTitle" tick={{ fill: '#4B5563', fontSize: 12 }} />
                     <PolarRadiusAxis angle={30} domain={[0, 10]} tickCount={6} />
                     <Radar
                       name="Média"
                       dataKey="average"
                       stroke="#2563EB"
                       strokeWidth={3}
                       fill="#3B82F6"
                       fillOpacity={0.5}
                     />
                     <Tooltip 
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                     />
                   </RadarChart>
                 </ResponsiveContainer>
               </div>

               <p className="text-sm text-gray-500 mt-4 italic">
                 Quanto mais próximo da borda externa (10), maior é o bloqueio nesta área.
               </p>
            </div>

            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
               <h3 className="text-xl font-semibold text-gray-800 mb-6 flex items-center gap-2">
                 <BarChart2 className="text-blue-500" size={24}/>
                 Detalhamento por Área (Média 0-10)
               </h3>

               <div className="w-full h-[300px]">
                 <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={calculateResults} layout="vertical" margin={{ left: 40, right: 40 }}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                      <XAxis type="number" domain={[0, 10]} hide />
                      <YAxis dataKey="travaTitle" type="category" width={100} tick={{ fontSize: 12, fontWeight: 500 }} />
                      <Tooltip 
                        cursor={{fill: 'transparent'}}
                        contentStyle={{ borderRadius: '8px' }}
                      />
                      <Bar dataKey="average" name="Média" radius={[0, 4, 4, 0]}>
                         {calculateResults.map((entry, index) => (
                           <Cell key={`cell-${index}`} fill={entry.average > 5 ? '#EF4444' : entry.average > 3 ? '#F59E0B' : '#10B981'} />
                         ))}
                      </Bar>
                    </BarChart>
                 </ResponsiveContainer>
               </div>
            </div>

            {/* Priority Alerts (> 5) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {calculateResults.filter(r => r.average > 5).map(high => (
                <div key={high.travaTitle} className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-start gap-3">
                  <div className="bg-red-100 p-2 rounded-full text-red-600 mt-1">
                    <AlertTriangle size={20} />
                  </div>
                  <div>
                    <div className="flex items-center justify-between mb-1 gap-2">
                      <h4 className="font-bold text-red-800">{high.travaTitle}</h4>
                      <span className="bg-red-200 text-red-800 text-xs font-bold px-2 py-1 rounded">Média: {high.average}</span>
                    </div>
                    <p className="text-sm text-red-600 font-medium">Merece atenção prioritária.</p>
                  </div>
                </div>
              ))}
            </div>

            {/* Admin Action Buttons */}
            <div className="flex flex-col sm:flex-row justify-center gap-4 pt-8 print:hidden">
              <button 
                onClick={() => window.print()}
                className="bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1"
              >
                <Printer size={20} />
                Imprimir / Salvar PDF
              </button>

              <button 
                onClick={notifyUserViaWhatsApp}
                className="bg-green-500 hover:bg-green-600 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1"
              >
                <MessageCircle size={20} />
                Avisar Cliente (WhatsApp)
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Cell } from 'recharts';
import { Lock, User, Phone, CheckCircle, ChevronRight, ChevronLeft, BarChart2, Brain, Play, Printer, MessageCircle, AlertTriangle, ShieldCheck, Send, Database, Trash2, Calendar, ArrowLeft, RotateCcw } from 'lucide-react';
import { TRAVAS_DATA } from './constants';
import { UserData, Answers, TravaResult, Submission } from './types';

export default function App() {
  // Steps: 
  // 'intro': User start screen
  // 'quiz': User answering questions
  // 'submission': User finished, sees success message
  // 'admin_login': Admin entering password
  // 'admin_dashboard': List of all saved submissions
  // 'results': Admin viewing charts
  const [step, setStep] = useState<'intro' | 'quiz' | 'submission' | 'admin_login' | 'admin_dashboard' | 'results'>('intro');

  const [userData, setUserData] = useState<UserData>({ name: '', phone: '' });
  const [answers, setAnswers] = useState<Answers>({});

  // Admin State
  const [adminPassword, setAdminPassword] = useState('');
  const [dbHistory, setDbHistory] = useState<Submission[]>([]);

  // Quiz Navigation State
  const [currentTravaIndex, setCurrentTravaIndex] = useState(0);

  // Load DB on mount
  useEffect(() => {
    const stored = localStorage.getItem('travas_db_v1');
    if (stored) {
      try {
        setDbHistory(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const saveToHistory = (submission: Submission) => {
    // Save to State and LocalStorage
    const newHistory = [submission, ...dbHistory];
    setDbHistory(newHistory);
    localStorage.setItem('travas_db_v1', JSON.stringify(newHistory));
  };

  const deleteFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Tem certeza que deseja excluir este registro?')) {
      const newHistory = dbHistory.filter(item => item.id !== id);
      setDbHistory(newHistory);
      localStorage.setItem('travas_db_v1', JSON.stringify(newHistory));
    }
  };

  const handleStart = () => {
    if (userData.name.trim().length > 0 && userData.phone.trim().length > 0) {
      setStep('quiz');
      window.scrollTo(0, 0);
    } else {
      alert('Por favor, preencha seu nome e telefone para iniciar.');
    }
  };

  const handleAnswer = (questionId: string, value: number) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleNextTrava = () => {
    if (currentTravaIndex < TRAVAS_DATA.length - 1) {
      setCurrentTravaIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    } else {
      // User finished the quiz - Save Automatically
      handleFinishQuiz();
    }
  };

  const handlePrevTrava = () => {
    if (currentTravaIndex > 0) {
      setCurrentTravaIndex(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const handleFinishQuiz = () => {
     // Pack data with ID and Timestamp
    const submission: Submission = { 
      id: Date.now().toString(),
      submittedAt: new Date().toISOString(),
      userData, 
      answers 
    };

    saveToHistory(submission);
    setStep('submission');
    window.scrollTo(0, 0);
  };

  const handleNewAnalysis = () => {
    setUserData({ name: '', phone: '' });
    setAnswers({});
    setCurrentTravaIndex(0);
    setStep('intro');
    window.scrollTo(0, 0);
  };

  const calculateResults = useMemo((): TravaResult[] => {
    return TRAVAS_DATA.map(trava => {
      let total = 0;
      trava.questions.forEach(q => {
        total += answers[q.id] || 0;
      });
      const average = total / trava.questions.length;
      return {
        travaTitle: trava.title.replace('Trava da ', '').replace('Trava ', ''), // Shorten name for chart
        average: parseFloat(average.toFixed(1)),
        totalScore: total
      };
    });
  }, [answers]);

  const isCurrentPageComplete = useMemo(() => {
    const currentTrava = TRAVAS_DATA[currentTravaIndex];
    return currentTrava.questions.every(q => answers[q.id] !== undefined);
  }, [answers, currentTravaIndex]);


  // --- ADMIN ACTIONS ---

  // Admin Login Logic
  const handleAdminLogin = () => {
    if (adminPassword === 'admin') { 
        setStep('admin_dashboard');
    } else {
      alert("Senha incorreta.");
    }
  };

  const notifyUserViaWhatsApp = () => {
    const message = `Olá ${userData.name}, sua análise de Travas Emocionais está pronta!`;
    const cleanPhone = userData.phone.replace(/\D/g, '');
    window.open(`https://wa.me/55${cleanPhone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  // Load a historic item
  const loadSubmission = (sub: Submission) => {
    setUserData(sub.userData);
    setAnswers(sub.answers);
    setStep('results');
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans selection:bg-blue-200">

      {/* Header */}
      <header className="bg-white shadow-sm sticky top-0 z-20 print:hidden">
        <div className="max-w-3xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Lock size={20} />
            </div>
            <h1 className="text-lg font-bold text-gray-800 leading-tight">
              Mapeamento <br className="sm:hidden"/> de Travas
            </h1>
          </div>
          {step === 'quiz' && (
             // Simple progress indicator
            <div className="flex gap-1">
                 {TRAVAS_DATA.map((_, idx) => (
                    <div 
                        key={idx} 
                        className={`h-2 w-2 rounded-full transition-all ${idx === currentTravaIndex ? 'bg-blue-600 w-4' : idx < currentTravaIndex ? 'bg-blue-200' : 'bg-gray-200'}`}
                    />
                 ))}
            </div>
          )}
          {(step === 'results' || step === 'admin_dashboard') && (
             <div className="text-xs bg-red-100 text-red-800 px-2 py-1 rounded font-bold uppercase flex items-center gap-1">
               <ShieldCheck size={12} /> Admin
             </div>
          )}
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-8 pb-24">

        {/* STEP 1: INTRO & FORM */}
        {step === 'intro' && (
          <div className="space-y-8 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
              <div className="text-center mb-6">
                <div className="bg-blue-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                  <Brain size={40} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">Descubra seus Bloqueios</h2>
                <p className="text-gray-600">
                  Ferramenta de autoanálise para identificar travas emocionais.
                </p>
              </div>

              {/* Video Presentation */}
              <div className="rounded-xl overflow-hidden shadow-md aspect-video bg-gray-100">
                <iframe 
                  className="w-full h-full"
                  src="https://www.youtube.com/embed/b_dPrk4g_ok" 
                  title="Apresentação Mapeamento de Travas"
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                  allowFullScreen
                ></iframe>
              </div>

              {/* NEW TEXT REQUIRED */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 text-sm text-blue-800 leading-relaxed text-center">
                Faça o formulario com calma e reflita cada pergunta pensando no hoje, no que esta vivendo agora no seu momento presente. Terminando as informações da travas serão enviada no seu celular.
              </div>

              <div className="space-y-5 pt-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu Nome</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="text"
                      placeholder="Digite seu nome completo"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.name}
                      onChange={(e) => setUserData({ ...userData, name: e.target.value })}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Seu WhatsApp</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="tel"
                      placeholder="(00) 00000-0000"
                      className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      value={userData.phone}
                      onChange={(e) => setUserData({ ...userData, phone: e.target.value })}
                    />
                  </div>
                </div>

                <button
                  onClick={handleStart}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 mt-4"
                >
                  <span>Iniciar Mapeamento</span>
                  <Play size={20} fill="currentColor" />
                </button>
              </div>
            </div>

            <div className="text-center">
                <button 
                    onClick={() => setStep('admin_login')}
                    className="text-xs text-gray-400 hover:text-gray-600 font-medium underline"
                >
                    Acesso Administrativo
                </button>
            </div>
          </div>
        )}

        {/* STEP 2: QUIZ */}
        {step === 'quiz' && (
          <div className="space-y-6">

            {/* Top Navigation / Progress */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 overflow-x-auto">
                 <div className="flex items-center gap-2 min-w-max">
                     {TRAVAS_DATA.map((t, idx) => (
                         <button 
                            key={t.id}
                            onClick={() => {
                                // Only allow clicking if we are jumping back or to a completed section (simplified validation)
                                if(idx <= currentTravaIndex) setCurrentTravaIndex(idx);
                            }}
                            className={`flex flex-col items-center justify-center w-8 h-8 rounded-full text-xs font-bold transition-all ${
                                idx === currentTravaIndex 
                                ? 'bg-blue-600 text-white shadow-md scale-110' 
                                : idx < currentTravaIndex 
                                    ? 'bg-blue-100 text-blue-600 cursor-pointer hover:bg-blue-200' 
                                    : 'bg-gray-100 text-gray-400'
                            }`}
                         >
                            {idx + 1}
                         </button>
                     ))}
                     <span className="text-xs font-medium text-gray-500 ml-2">
                        {TRAVAS_DATA[currentTravaIndex].title.replace('Trava ', '')}
                     </span>
                 </div>
            </div>

            <div className="bg-white rounded-2xl shadow-md p-6 border-l-4 border-blue-500">
              <h2 className="text-xl font-bold text-gray-800 mb-2">{TRAVAS_DATA[currentTravaIndex].title}</h2>
              <p className="text-gray-600 text-sm leading-relaxed">{TRAVAS_DATA[currentTravaIndex].description}</p>
            </div>

            <div className="space-y-6">
              {TRAVAS_DATA[currentTravaIndex].questions.map((question, qIdx) => (
                <div key={question.id} className="bg-white rounded-xl shadow-sm p-5 sm:p-6 transition-colors border border-transparent hover:border-blue-100">
                  <div className="flex justify-between items-start mb-4 gap-4">
                    <span className="bg-gray-100 text-gray-500 text-xs font-bold px-2 py-1 rounded">
                      {qIdx + 1}/5
                    </span>
                    <h3 className="text-gray-800 font-medium flex-1 pt-0.5">{question.text}</h3>
                  </div>

                  <div className="pt-2">
                    <div className="flex justify-between text-xs text-gray-500 mb-2 uppercase tracking-wide">
                      <span>Discordo (0)</span>
                      <span>Concordo Muito (10)</span>
                    </div>
                    <input
                      type="range"
                      min="0"
                      max="10"
                      step="1"
                      value={answers[question.id] ?? 0}
                      onChange={(e) => handleAnswer(question.id, parseInt(e.target.value))}
                      className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600 focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                    />
                    <div className="mt-3 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full text-sm font-bold ${
                        (answers[question.id] ?? 0) > 7 ? 'bg-red-100 text-red-700' :
                        (answers[question.id] ?? 0) > 4 ? 'bg-yellow-100 text-yellow-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        Nota: {answers[question.id] ?? 0}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 z-10 shadow-lg">
              <div className="max-w-3xl mx-auto flex items-center justify-between gap-4">

                <button
                    onClick={handlePrevTrava}
                    disabled={currentTravaIndex === 0}
                    className={`px-4 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
                        currentTravaIndex === 0 
                        ? 'text-gray-300 cursor-not-allowed' 
                        : 'text-gray-600 hover:bg-gray-100'
                    }`}
                >
                    <ChevronLeft size={20} />
                    <span className="hidden sm:inline">Anterior</span>
                </button>

                <button
                  onClick={handleNextTrava}
                  disabled={!isCurrentPageComplete}
                  className={`flex-1 sm:flex-none sm:w-auto px-8 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
                    isCurrentPageComplete 
                      ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-md transform hover:-translate-y-1' 
                      : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? 'Concluir Análise' : 'Próxima Trava'}
                  {currentTravaIndex === TRAVAS_DATA.length - 1 ? <CheckCircle size={18} /> : <ChevronRight size={18} />}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* STEP 3: SUBMISSION (COMPLETION SCREEN) */}
        {step === 'submission' && (
          <div className="space-y-8 animate-fade-in text-center py-10">
            <div className="bg-white rounded-2xl shadow-lg p-10 border border-gray-100">
               <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
                 <Brain size={48} />
               </div>

               <h2 className="text-3xl font-bold text-gray-900 mb-4">Parabéns!</h2>

               <div className="bg-green-50 border border-green-100 rounded-xl p-6 mb-8 max-w-md mx-auto">
                   <p className="text-green-800 text-lg font-medium leading-relaxed">
                     Suas respostas foram registradas com sucesso. Logo será enviado o resultado das perguntas.
                   </p>
               </div>

               <button 
                 onClick={handleNewAnalysis}
                 className="inline-flex items-center gap-2 text-gray-500 hover:text-blue-600 font-medium transition-colors mt-4"
               >
                 <RotateCcw size={18} />
                 Iniciar Nova Análise
               </button>
            </div>
          </div>
        )}

        {/* STEP 4: ADMIN LOGIN */}
        {step === 'admin_login' && (
           <div className="space-y-8 animate-fade-in max-w-md mx-auto">
             <div className="bg-white rounded-2xl shadow-lg p-8 border border-gray-100">
               <div className="text-center mb-6">
                 <div className="bg-gray-800 text-white w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                   <ShieldCheck size={32} />
                 </div>
                 <h2 className="text-xl font-bold text-gray-800">Acesso Administrativo</h2>
                 <p className="text-sm text-gray-500 mt-2">
                   Entre para acessar o banco de dados
                 </p>
               </div>

               <div className="space-y-4">
                 <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Senha de Admin</label>
                   <input
                      type="password"
                      className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-gray-500 outline-none"
                      placeholder="Digite a senha..."
                      value={adminPassword}
                      onChange={(e) => setAdminPassword(e.target.value)}
                    />
                 </div>
                 <button
                    onClick={handleAdminLogin}
                    className="w-full bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 rounded-xl transition-all"
                 >
                   Entrar
                 </button>
               </div>
             </div>

             <div className="text-center">
                <button onClick={() => setStep('intro')} className="text-gray-500 underline text-sm">
                    Voltar para Início
                </button>
             </div>
           </div>
        )}

        {/* STEP 5: ADMIN DASHBOARD (DATABASE) */}
        {step === 'admin_dashboard' && (
          <div className="space-y-6 animate-fade-in">
             <div className="flex items-center justify-between mb-4">
                <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                  <Database className="text-blue-600" />
                  Banco de Dados
                </h2>
                <div className="flex items-center gap-4">
                    <button 
                        onClick={() => setStep('intro')}
                        className="text-sm text-blue-600 font-medium hover:underline"
                    >
                        Ir para Início
                    </button>
                    <div className="bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-xs font-bold">
                        {dbHistory.length} Registros
                    </div>
                </div>
             </div>

             {dbHistory.length === 0 ? (
               <div className="bg-white rounded-xl p-8 text-center text-gray-500 border border-dashed border-gray-300">
                 <p>Nenhuma análise salva ainda.</p>
               </div>
             ) : (
               <div className="grid gap-3">
                 {dbHistory.map((item) => (
                   <div key={item.id} onClick={() => loadSubmission(item)} className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all cursor-pointer flex items-center justify-between group">
                      <div className="flex items-center gap-4">
                         <div className="bg-blue-50 w-10 h-10 rounded-full flex items-center justify-center text-blue-600 font-bold">
                           {item.userData.name.charAt(0).toUpperCase()}
                         </div>
                         <div>
                           <h4 className="font-bold text-gray-800">{item.userData.name}</h4>
                           <div className="flex items-center gap-3 text-xs text-gray-500">
                             <span className="flex items-center gap-1"><Phone size={12}/> {item.userData.phone}</span>
                             <span className="flex items-center gap-1"><Calendar size={12}/> {new Date(item.submittedAt || Date.now()).toLocaleDateString('pt-BR')}</span>
                           </div>
                         </div>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={(e) => deleteFromHistory(item.id, e)}
                          className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                          title="Excluir"
                        >
                          <Trash2 size={18} />
                        </button>
                        <ChevronRight className="text-gray-300 group-hover:text-blue-500" />
                      </div>
                   </div>
                 ))}
               </div>
             )}
          </div>
        )}

        {/* STEP 6: RESULTS (ADMIN ONLY) */}
        {step === 'results' && (
          <div className="space-y-8 animate-fade-in-up">

            {/* Nav Back */}
            <button 
              onClick={() => setStep('admin_dashboard')}
              className="flex items-center gap-2 text-gray-500 hover:text-gray-800 font-medium transition-colors"
            >
              <ArrowLeft size={18} /> Voltar para o Painel
            </button>

            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100 text-center">
               <div className="mb-2 uppercase tracking-wider text-xs font-bold text-gray-400">Relatório de</div>
               <h2 className="text-3xl font-bold text-blue-900 mb-1">{userData.name}</h2>
               <p className="text-gray-500 text-sm mb-6">{userData.phone}</p>

               <div className="w-full h-1 bg-gray-100 rounded mb-8"></div>

               <h3 className="text-xl font-semibold text-gray-800 mb-4 flex items-center justify-center gap-2">
                 <CheckCircle className="text-green-500" size={24}/>
                 Mapa Radar das Travas
               </h3>

               <div className="w-full h-[400px] flex items-center justify-center -ml-4">
                 <ResponsiveContainer width="100%" height="100%">
                   <RadarChart cx="50%" cy="50%" outerRadius="80%" data={calculateResults}>
                     <PolarGrid gridType="polygon" />
                     <PolarAngleAxis dataKey="travaTitle" tick={{ fill: '#4B5563', fontSize: 12 }} />
                     <PolarRadiusAxis angle={30} domain={[0, 10]} tickCount={6} />
                     <Radar
                       name="Média"
                       dataKey="average"
                       stroke="#2563EB"
                       strokeWidth={3}
                       fill="#3B82F6"
                       fillOpacity={0.5}
                     />
                     <Tooltip 
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                     />
                   </RadarChart>
                 </ResponsiveContainer>
               </div>

               <p className="text-sm text-gray-500 mt-4 italic">
                 Quanto mais próximo da borda externa (10), maior é o bloqueio nesta área.
               </p>
            </div>

            <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-10 border border-gray-100">
               <h3 className="text-xl font-semibold text-gray-800 mb-6 flex items-center gap-2">
                 <BarChart2 className="text-blue-500" size={24}/>
                 Detalhamento por Área (Média 0-10)
               </h3>

               <div className="w-full h-[300px]">
                 <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={calculateResults} layout="vertical" margin={{ left: 40, right: 40 }}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                      <XAxis type="number" domain={[0, 10]} hide />
                      <YAxis dataKey="travaTitle" type="category" width={100} tick={{ fontSize: 12, fontWeight: 500 }} />
                      <Tooltip 
                        cursor={{fill: 'transparent'}}
                        contentStyle={{ borderRadius: '8px' }}
                      />
                      <Bar dataKey="average" name="Média" radius={[0, 4, 4, 0]}>
                         {calculateResults.map((entry, index) => (
                           <Cell key={`cell-${index}`} fill={entry.average > 5 ? '#EF4444' : entry.average > 3 ? '#F59E0B' : '#10B981'} />
                         ))}
                      </Bar>
                    </BarChart>
                 </ResponsiveContainer>
               </div>
            </div>

            {/* Priority Alerts (> 5) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {calculateResults.filter(r => r.average > 5).map(high => (
                <div key={high.travaTitle} className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-start gap-3">
                  <div className="bg-red-100 p-2 rounded-full text-red-600 mt-1">
                    <AlertTriangle size={20} />
                  </div>
                  <div>
                    <div className="flex items-center justify-between mb-1 gap-2">
                      <h4 className="font-bold text-red-800">{high.travaTitle}</h4>
                      <span className="bg-red-200 text-red-800 text-xs font-bold px-2 py-1 rounded">Média: {high.average}</span>
                    </div>
                    <p className="text-sm text-red-600 font-medium">Merece atenção prioritária.</p>
                  </div>
                </div>
              ))}
            </div>

            {/* Admin Action Buttons */}
            <div className="flex flex-col sm:flex-row justify-center gap-4 pt-8 print:hidden">
              <button 
                onClick={() => window.print()}
                className="bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1"
              >
                <Printer size={20} />
                Imprimir / Salvar PDF
              </button>

              <button 
                onClick={notifyUserViaWhatsApp}
                className="bg-green-500 hover:bg-green-600 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1"
              >
                <MessageCircle size={20} />
                Avisar Cliente (WhatsApp)
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Cell } from 'recharts';
import { Lock, User, Phone, CheckCircle, ChevronRight, ChevronLeft, BarChart2, Brain, Play, Printer, MessageCircle, AlertTriangle, ShieldCheck, Database, Trash2, Calendar, ArrowLeft, RotateCcw, Info } from 'lucide-react';
import { TRAVAS_DATA } from './constants';
import { UserData, Answers, TravaResult, Submission } from './types';

export default function App() {
  // Steps: 
  // 'intro': Tela inicial do usuário
  // 'quiz': Respondendo perguntas
  // 'submission': Tela de parabéns/conclusão
  // 'admin_login': Login administrativo
  // 'admin_dashboard': Lista de registros (Banco de Dados)
  // 'results': Visualização dos gráficos (Admin)
  const [step, setStep] = useState<'intro' | 'quiz' | 'submission' | 'admin_login' | 'admin_dashboard' | 'results'>('intro');

  const [userData, setUserData] = useState<UserData>({ name: '', phone: '' });
  const [answers, setAnswers] = useState<Answers>({});

  // Admin State
  const [adminPassword, setAdminPassword] = useState('');
  const [dbHistory, setDbHistory] = useState<Submission[]>([]);

  // Quiz Navigation State
  const [currentTravaIndex, setCurrentTravaIndex] = useState(0);

  // Carregar Banco de Dados local ao iniciar
  useEffect(() => {
    const stored = localStorage.getItem('travas_db_v1');
    if (stored) {
      try {
        setDbHistory(JSON.parse(stored));
      } catch (e) {
        console.error("Falha ao carregar histórico", e);
      }
    }
  }, []);

  const saveToHistory = (submission: Submission) => {
    const newHistory = [submission, ...dbHistory];
    setDbHistory(newHistory);
    localStorage.setItem('travas_db_v1', JSON.stringify(newHistory));
  };

  const deleteFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      const newHistory = dbHistory.filter(item => item.id !== id);
      setDbHistory(newHistory);
      localStorage.setItem('travas_db_v1', JSON.stringify(newHistory));
    }
  };

  const handleStart = () => {
    if (userData.name.trim().length > 0 && userData.phone.trim().length > 0) {
      setStep('quiz');
      window.scrollTo(0, 0);
    } else {
      alert('Por favor, preencha seu nome e telefone para iniciar.');
    }
  };

  const handleAnswer = (questionId: string, value: number) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleNextTrava = () => {
    if (currentTravaIndex < TRAVAS_DATA.length - 1) {
      setCurrentTravaIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    } else {
      handleFinishQuiz();
    }
  };

  const handlePrevTrava = () => {
    if (currentTravaIndex > 0) {
      setCurrentTravaIndex(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const handleFinishQuiz = () => {
    const submission: Submission = { 
      id: Date.now().toString(),
      submittedAt: new Date().toISOString(),
      userData, 
      answers 
    };
    saveToHistory(submission);
    setStep('submission');
    window.scrollTo(0, 0);
  };

  const handleNewAnalysis = () => {
    setUserData({ name: '', phone: '' });
    setAnswers({});
    setCurrentTravaIndex(0);
    setStep('intro');
    window.scrollTo(0, 0);
  };

  const calculateResults = useMemo((): TravaResult[] => {
    return TRAVAS_DATA.map(trava => {
      let total = 0;
      trava.questions.forEach(q => {
        total += answers[q.id] || 0;
      });
      const average = total / trava.questions.length;
      return {
        travaTitle: trava.title.replace('Trava da ', '').replace('Trava ', ''),
        average: parseFloat(average.toFixed(1)),
        totalScore: total
      };
    });
  }, [answers]);

  const isCurrentPageComplete = useMemo(() => {
    const currentTrava = TRAVAS_DATA[currentTravaIndex];
    return currentTrava.questions.every(q => answers[q.id] !== undefined);
  }, [answers, currentTravaIndex]);

  const handleAdminLogin = () => {
    if (adminPassword === 'admin') { 
        setStep('admin_dashboard');
    } else {
      alert("Senha incorreta.");
    }
  };

  const notifyUserViaWhatsApp = () => {
    const message = `Olá ${userData.name}, sua análise de Travas Emocionais está pronta!`;
    const cleanPhone = userData.phone.replace(/\D/g, '');
    window.open(`https://wa.me/55${cleanPhone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  const loadSubmission = (sub: Submission) => {
    setUserData(sub.userData);
    setAnswers(sub.answers);
    setStep('results');
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans selection:bg-blue-100 pb-10">

      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-30 print:hidden border-b border-slate-100">
        <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl text-white shadow-blue-200 shadow-lg">
              <Brain size={22} />
            </div>
            <div>
              <h1 className="text-base font-bold text-slate-900 leading-tight">
                Mapeamento <br className="sm:hidden"/> de Travas
              </h1>
            </div>
          </div>

          {step === 'quiz' && (
            <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-full">
